template <>
inline auto
transform<2, 0>(CDenseMatrix &spherical, const CDenseMatrix &cartesian) -> void
{
    const auto npairs = cartesian.getNumberOfColumns();
    const auto nblocks = cartesian.getNumberOfRows() / 6;
    auto *sph = spherical.values();
    const auto *car = cartesian.values();
    for (int n = 0; n < nblocks; n++)
    {
        const auto coff = static_cast<size_t>(n) * 6 * npairs;
        const auto soff = static_cast<size_t>(n) * 5 * npairs;
        {
            auto *dst = sph + soff + 0 * npairs;
            const auto *src0 = car + coff + 1 * npairs;
#pragma omp simd
            for (int p = 0; p < npairs; p++)
            {
                dst[p] += 1.7320508075688772 * src0[p];
            }
        }
        {
            auto *dst = sph + soff + 1 * npairs;
            const auto *src0 = car + coff + 4 * npairs;
#pragma omp simd
            for (int p = 0; p < npairs; p++)
            {
                dst[p] += 1.7320508075688772 * src0[p];
            }
        }
        {
            auto *dst = sph + soff + 2 * npairs;
            const auto *src0 = car + coff + 0 * npairs;
            const auto *src1 = car + coff + 3 * npairs;
            const auto *src2 = car + coff + 5 * npairs;
#pragma omp simd
            for (int p = 0; p < npairs; p++)
            {
                dst[p] += -0.5 * src0[p] + -0.5 * src1[p] + 1.0 * src2[p];
            }
        }
        {
            auto *dst = sph + soff + 3 * npairs;
            const auto *src0 = car + coff + 2 * npairs;
#pragma omp simd
            for (int p = 0; p < npairs; p++)
            {
                dst[p] += 1.7320508075688772 * src0[p];
            }
        }
        {
            auto *dst = sph + soff + 4 * npairs;
            const auto *src0 = car + coff + 0 * npairs;
            const auto *src1 = car + coff + 3 * npairs;
#pragma omp simd
            for (int p = 0; p < npairs; p++)
            {
                dst[p] += 0.8660254037844386 * src0[p] + -0.8660254037844386 * src1[p];
            }
        }
    }
}

